import React from 'react';
import { motion } from 'framer-motion';
import { useInView } from 'react-intersection-observer';
import { FaGraduationCap, FaCode, FaTrophy, FaLaptopCode } from 'react-icons/fa';
import './About.css';

const About = () => {
  const [ref, inView] = useInView({
    triggerOnce: true,
    threshold: 0.1
  });

  const stats = [
    { icon: <FaCode />, value: '1000+', label: 'Problems Solved' },
    { icon: <FaTrophy />, value: '80+', label: 'Contests' },
    { icon: <FaGraduationCap />, value: '8.92', label: 'CGPA' },
    { icon: <FaLaptopCode />, value: '10+', label: 'Projects' }
  ];

  return (
    <section className="about" id="about">
      <div className="container">
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 50 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
        >
          <h2 className="section-title">About Me</h2>

          <div className="about-content">
            <div className="about-text">
              <p className="lead">
                I'm an analytical B.Tech graduate in Artificial Intelligence and Data Science 
                from KIT - Kalaignar Karunanidhi Institute of Technology, Coimbatore.
              </p>
              
              <p>
                With proficiency in data structures, C, C++, and Python, I specialize in 
                web development, scripting, and competitive programming. My expertise spans 
                across data analysis and machine learning, where I combine technical accuracy 
                with innovative thinking to tackle challenging problems.
              </p>

              <p>
                I'm passionate about creating efficient solutions and continuously learning 
                new technologies. My experience includes freelance development, where I've 
                successfully delivered customized solutions for multiple clients.
              </p>

              <div className="education-card">
                <div className="education-icon">
                  <FaGraduationCap />
                </div>
                <div className="education-details">
                  <h3>B.Tech – Artificial Intelligence and Data Science</h3>
                  <p className="institution">KIT - Kalaignar Karunanidhi Institute of Technology</p>
                  <p className="location">Coimbatore, India</p>
                  <div className="education-meta">
                    <span className="cgpa">CGPA: 8.92</span>
                    <span className="year">Expected: January 2028</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="stats-grid">
              {stats.map((stat, index) => (
                <motion.div
                  key={index}
                  className="stat-card"
                  initial={{ opacity: 0, scale: 0.5, rotateY: -180 }}
                  animate={inView ? { opacity: 1, scale: 1, rotateY: 0 } : {}}
                  transition={{ 
                    delay: index * 0.15, 
                    duration: 0.8,
                    type: "spring",
                    stiffness: 100
                  }}
                  whileHover={{ 
                    y: -15, 
                    scale: 1.05,
                    boxShadow: "0 20px 40px rgba(0, 0, 0, 0.15)",
                    transition: { duration: 0.3 }
                  }}
                >
                  <div className="stat-icon">{stat.icon}</div>
                  <h3>{stat.value}</h3>
                  <p>{stat.label}</p>
                </motion.div>
              ))}
            </div>
          </div>
        </motion.div>
      </div>
    </section>
  );
};

export default About;
